function Section({ title, children }) {
  return (
    <View>
      <Text style={styles.title}>{title}</Text>
      <View style={styles.content}>
        {children}
      </View>
    </View>
  );
}

// Usage
<Section title="About Me">
  <Text>I love coding.</Text>
  <Text>I also love coffee.</Text>
</Section>
